SELECT SUM(sc.total_amount) AS sellTotalAmount, SUM(bc.total_amount) AS buyTotalAmount, SUM(sc.total_amount - bc.total_amount) AS profit, SUM(bc.warehouse_amount + bc.transport_amount + sc.warehouse_amount + sc.transport_amount + bc.delivery_fee + sc.delivery_fee) AS cost, SUM(sc.total_amount - bc.total_amount - bc.warehouse_amount - bc.transport_amount - sc.warehouse_amount - sc.transport_amount - bc.delivery_fee - sc.delivery_fee - sc.stevedorage - bc.stevedorage) AS margin FROM t_ctr_contract_rela r LEFT JOIN t_ctr_contract bc ON bc.id = r.buy_contract_id LEFT JOIN t_ctr_contract sc ON sc.id = r.sell_contract_id WHERE sc.seal_flg = TRUE and bc.seal_flg = TRUE AND sc.enterprise_id = #{enterpriseId}
AND DATE_FORMAT(sc.contract_time, '%Y-%m-%d') >= DATE_FORMAT(#{contractTimeStart}, '%Y-%m-%d')
AND DATE_FORMAT(sc.contract_time, '%Y-%m-%d') <= DATE_FORMAT(#{contractTimeEnd}, '%Y-%m-%d')
AND DATE_FORMAT(sc.contract_time, '%Y-%m-%d') >= DATE_FORMAT(#{contractTimeStart}, '%Y-%m-%d')
AND DATE_FORMAT(sc.contract_time, '%Y-%m-%d') <= DATE_FORMAT(#{contractTimeEnd}, '%Y-%m-%d')
AND sc.dept_id = #{deptId}
and sc.dept_id in
#{myDeptIdList[${index}],jdbcType=VARCHAR}
AND sc.business_type = 'ZY-BB' AND sc.match_credit_flg = TRUE
AND sc.business_type = 'ZY-BB' AND sc.match_credit_flg = FALSE
AND sc.business_type != 'ZY-BB'
AND sc.match_user_id = #{matchUserId}

SELECT t1.buType as businessTypeDesc, s.contract_no AS contractNo, s.company_name AS companyName, s.match_user_name As sellMatchUserName, b.match_user_name As buyMatchUserName, s.total_number AS totalNumber, s.total_amount AS sellTotalAmount, b.total_amount AS buyTotalAmount, b.deal_price AS buyPrice, s.deal_price AS sellPrice, b.pay_full_time AS payDate, s.real_pay_full_time receiveDate, s.appoint_pay_full_time AS appointPayDate, s.confirm_date AS confirmReceiptDate, IFNULL((b.transport_amount + s.transport_amount),0) AS transportAmount, IFNULL((b.warehouse_amount + s.warehouse_amount),0) AS warehouseAmount, s.breach_days AS breachDay, s.breach_amount AS breachAmount, s.credit_cycle AS creditCycle, case when s.delivery_fee is null then 0 else s.delivery_fee end as deliveryFee FROM t_ctr_contract_rela r LEFT JOIN t_ctr_contract b ON r.buy_contract_id = b.id LEFT JOIN t_ctr_contract s ON r.sell_contract_id = s.id LEFT JOIN (SELECT id, CASE WHEN match_credit_flg = 1 AND business_type = 'ZY-BB' THEN '赊销' WHEN business_type IN ( 'ZY-CG', 'ZY-XS' ) THEN '自营' WHEN match_credit_flg = 0 AND business_type = 'ZY-BB' THEN '代采' ELSE '其他' END AS buType FROM t_ctr_contract ) AS t1 ON t1.id = b.id WHERE s.business_type = 'ZY-BB' AND s.`status` != 'C'
AND s.contract_no like concat('%',#{contractNo},'%')
AND t1.buType = #{buType}
AND s.match_user_name = #{sellMatchUserName}
AND b.match_user_name = #{buyMatchUserName}
AND s.real_pay_full_time >= #{contractTimeStart}
AND s.real_pay_full_time<= #{contractTimeEnd}
AND s.real_pay_full_time = #{contractTimeStart}
AND s.real_pay_full_time = #{contractTimeEnd}
ORDER BY r.updated_date DESC

SELECT
   SUM(c.total_number) AS totalNubmer,
   SUM(c.warehouse_number) AS warehouseNumber,
   SUM(c.total_amount) AS totalAmount,
   SUM(c.dealed_amount) AS dealedAmount,
   SUM(c.billed_amount) AS billedAmount,
   SUM(c.insurance_amount) AS interestAmount,
   SUM(IF(c.total_amount < c.dealed_amount, 0, (c.total_amount-c.dealed_amount))) AS receivableBalance
FROM t_ctr_contract c
left join t_ctr_contract_text t on c.id = t.ctr_contract_id
LEFT JOIN t_ctr_contract buy ON c.approve_id = buy.approve_id AND buy.contract_type = 'B'
LEFT JOIN t_ctr_contract sell ON c.approve_id = sell.approve_id AND sell.contract_type = 'S'

	and buy.dealed_amount >= buy.total_amount
	and sell.seal_flg = true

		AND c.enterprise_id = #{searchParams.EQL_enterpriseId}


		AND c.business_type = #{searchParams.EQS_businessType}


		AND c.match_credit_flg = true


		AND c.match_credit_flg = false


		AND c.contract_type = #{searchParams.EQS_contractType}


		AND c.contract_no LIKE CONCAT('%',#{searchParams.LIKES_contractNo},'%')


		AND c.company_name LIKE CONCAT('%',#{searchParams.LIKES_companyName},'%')


		AND c.products_name LIKE CONCAT('%',#{searchParams.LIKES_productsName},'%')


		AND c.our_company_name LIKE CONCAT('%',#{searchParams.LIKES_ourCompanyName},'%')


		AND c.appoint_pay_full_time >= #{searchParams.GTED_payFullTime} 


		AND c.appoint_pay_full_time <= #{searchParams.LTD_payFullTime} 


		AND c.delivery_date_to >= #{searchParams.GTED_deliveryDateTo} 


		AND c.delivery_date_to <= #{searchParams.LTD_deliveryDateTo} 


		AND c.contract_time >= #{searchParams.GTED_contractTime} 


		AND c.contract_time <= #{searchParams.LTD_contractTime} 


		AND c.dealed_amount >= c.total_amount


		AND c.dealed_amount < c.total_amount


		AND c.warehouse_number >= c.total_number


		AND c.warehouse_number < c.total_number


		AND c.billed_amount >= c.total_amount


		AND c.billed_amount < c.total_amount


		AND c.credit_cycle >= #{searchParams.GTEL_creditCycle}


		AND c.credit_cycle <= #{searchParams.LTL_creditCycle}


		AND c.contract_status != 'C'


		AND c.contract_status = 'C'


		AND c.performance_status = #{searchParams.EQS_performanceStatus}


		AND c.match_user_id = #{searchParams.EQS_matchUserId}


		AND c.delivery_mode = #{searchParams.EQS_deliveryMode}


		AND DATE_FORMAT(c.pay_full_time, '%Y-%m-%d') != DATE_FORMAT(c.appoint_pay_full_time, '%Y-%m-%d')

