	AND c.confirm_receive_number >= c.total_number


	AND c.confirm_receive_number > 0 AND c.confirm_receive_number < c.total_number


	AND c.confirm_receive_number <= 0


	AND d.company_name LIKE CONCAT('%',#{fundCompanyName},'%')


	AND c.performance_status =#{performanceStatus}


