SELECT * FROM ( SELECT s.approve_id AS approveId, s.contract_no AS contractNo, CASE WHEN s.virtual_contract_no IS NOT NULL THEN v.contract_no ELSE s.contract_no END AS targetContractNo, '买' AS tag, '1' AS sort, 'B' AS contractType, s.our_company_name AS ourCompanyName, s.company_name AS companyName, s.products_name AS productNames, s.total_number AS totalNumber, s.appoint_pay_full_time AS appointPayFullTime, s.confirm_date AS confirmDate, (SELECT MAX( i.warehouse_in_date ) FROM t_apply_delivery_in i WHERE i.contract_no = targetContractNo AND i.`status` = 'D') AS deliveryDate, s.contract_time AS contractTime, s.deal_price AS dealPrice, s.total_amount AS totalAmount, s.credit_cycle AS creditDays, (SELECT MAX(r.pay_date) FROM t_apply_pay r WHERE r.contract_no = targetContractNo AND r.`status` = 'D') AS receiveDate, s.dealed_amount AS receiveAmount, (s.total_amount-s.dealed_amount) AS needReceiveAmount, s.billed_amount AS billAmount, (SELECT MAX(i.in_invoice_date) FROM t_apply_invoice_received i WHERE i.contract_no = targetContractNo AND i.`status` = 'D') AS billDate, s.company_id FROM t_ctr_contract s LEFT JOIN t_ctr_contract v ON s.virtual_contract_id = v.id WHERE s.approve_id IN
#{approveIdList[${index}],jdbcType=VARCHAR}
AND s.contract_type = 'B' AND s.special_chain_flag = false
UNION SELECT s.approve_id AS approveId, s.contract_no AS contractNo, CASE WHEN s.virtual_contract_no IS NOT NULL THEN v.contract_no ELSE s.contract_no END AS targetContractNo, '买' AS tag, '2' AS sort, 'B' AS contractType, s.our_company_name AS ourCompanyName, s.company_name AS companyName, s.products_name AS productNames, s.total_number AS totalNumber, s.appoint_pay_full_time AS appointPayFullTime, s.confirm_date AS confirmDate, (SELECT MAX( i.warehouse_in_date ) FROM t_apply_delivery_in i WHERE i.contract_no = targetContractNo AND i.`status` = 'D') AS deliveryDate, s.contract_time AS contractTime, s.deal_price AS dealPrice, s.total_amount AS totalAmount, s.credit_cycle AS creditDays, (SELECT MAX(r.pay_date) FROM t_apply_pay r WHERE r.contract_no = targetContractNo AND r.`status` = 'D') AS receiveDate, s.dealed_amount AS receiveAmount, (s.total_amount-s.dealed_amount) AS needReceiveAmount, s.billed_amount AS billAmount, (SELECT MAX(i.in_invoice_date) FROM t_apply_invoice_received i WHERE i.contract_no = targetContractNo AND i.`status` = 'D') AS billDate, s.company_id FROM t_ctr_contract s LEFT JOIN t_ctr_contract v ON s.virtual_contract_id = v.id WHERE s.approve_id IN
#{approveIdList[${index}],jdbcType=VARCHAR}
AND s.contract_type = 'B' AND s.special_chain_flag = true UNION
SELECT d.approve_id AS approveId, d.contract_no AS contractNo, '' AS targetContractNo, '买' AS tag, '3' AS sort, 'X' AS contractType, d.our_company_name AS ourCompanyName, d.company_name AS companyName, d.products_name AS productNames, d.total_number AS totalNumber, d.buy_pay_full_time AS appointPayFullTime, d.confirm_date AS confirmDate, null AS deliveryDate, d.contract_time AS contractTime, d.deal_price AS dealPrice, d.total_amount AS totalAmount, null AS creditDays, (SELECT MAX(p.pay_date) FROM t_apply_pay p WHERE p.contract_no = d.contract_no AND p.`status` = 'D') AS receiveDate, d.dealed_amount AS receiveAmount, (d.total_amount-d.dealed_amount) AS needReceiveAmount, d.billed_amount AS billAmount, COALESCE( (SELECT MAX(i.in_invoice_date) FROM t_apply_invoice_received i WHERE i.contract_no = d.contract_no AND i.status = 'D'), (SELECT MAX(i.invoice_date) FROM t_apply_invoice i WHERE i.contract_no = d.contract_no AND i.status = 'D') ) AS billDate, d.company_id FROM t_ctr_dcsx d WHERE d.id IN
#{contractIdList[${index}],jdbcType=VARCHAR}
UNION SELECT s.approve_id AS approveId, s.contract_no AS contractNo, '' AS targetContractNo, '卖' AS tag, '4' AS sort, 'S' AS contractType, s.our_company_name AS ourCompanyName, s.company_name AS companyName, s.products_name AS productNames, s.total_number AS totalNumber, s.appoint_pay_full_time AS appointPayFullTime, s.confirm_date AS confirmDate, (SELECT MAX(o.warehouse_out_date) FROM t_apply_delivery_out o WHERE o.contract_no = s.contract_no AND o.`status` = 'D') AS deliveryDate, s.contract_time AS contractTime, s.deal_price AS dealPrice, s.total_amount AS totalAmount, s.credit_cycle AS creditDays, (SELECT MAX(r.receive_date) FROM t_apply_receive r WHERE r.contract_no = s.contract_no AND r.`status` = 'D') AS receiveDate, s.dealed_amount AS receiveAmount, (s.total_amount-s.dealed_amount) AS needReceiveAmount, s.billed_amount AS billAmount, (SELECT MAX(i.invoice_date) FROM t_apply_invoice i WHERE i.contract_no = s.contract_no AND i.`status` = 'D') AS billDate, s.company_id FROM t_ctr_contract s WHERE s.approve_id IN
#{approveIdList[${index}],jdbcType=VARCHAR}
AND s.contract_type = 'S') t ORDER BY t.approveId DESC,t.sort ASC

SELECT match_user_id, sum(total_cost) as'totalCost' FROM t_rpt_base_cost WHERE base_date REGEXP '^[0-9]{4}-(0[1-9]|1[0-2])$'
AND base_date >=#{baseDateStart}
AND base_date <=#{baseDateEnd}
group by match_user_id
